const html = "<!doctype html>\n<html lang=\"he\" dir=\"rtl\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n  <title>שאלון אפיון למערכת הזמנות</title>\n  <style>\n    :root {\n      color-scheme: light;\n      --bg: #f6f7f8;\n      --panel: #ffffff;\n      --ink: #17202a;\n      --muted: #64707d;\n      --line: #dfe5eb;\n      --accent: #1c7c54;\n      --accent-dark: #145c3e;\n      --warn: #8a5a00;\n    }\n\n    * {\n      box-sizing: border-box;\n    }\n\n    body {\n      margin: 0;\n      font-family: Arial, \"Helvetica Neue\", sans-serif;\n      background: var(--bg);\n      color: var(--ink);\n      line-height: 1.55;\n    }\n\n    main {\n      width: min(920px, calc(100% - 28px));\n      margin: 0 auto;\n      padding: 28px 0 42px;\n    }\n\n    header {\n      margin-bottom: 22px;\n    }\n\n    h1 {\n      margin: 0 0 8px;\n      font-size: 30px;\n      line-height: 1.2;\n    }\n\n    .intro {\n      margin: 0;\n      color: var(--muted);\n      font-size: 16px;\n    }\n\n    form {\n      display: grid;\n      gap: 14px;\n    }\n\n    section {\n      background: var(--panel);\n      border: 1px solid var(--line);\n      border-radius: 8px;\n      padding: 18px;\n    }\n\n    h2 {\n      margin: 0 0 14px;\n      font-size: 20px;\n    }\n\n    label {\n      display: block;\n      font-weight: 700;\n      margin-bottom: 7px;\n    }\n\n    .field {\n      margin-bottom: 16px;\n    }\n\n    .field:last-child {\n      margin-bottom: 0;\n    }\n\n    input,\n    textarea,\n    select {\n      width: 100%;\n      border: 1px solid #cfd8e3;\n      border-radius: 7px;\n      padding: 11px 12px;\n      font: inherit;\n      color: var(--ink);\n      background: #fff;\n    }\n\n    textarea {\n      min-height: 92px;\n      resize: vertical;\n    }\n\n    .choices {\n      display: grid;\n      gap: 8px;\n    }\n\n    .choice {\n      display: flex;\n      align-items: flex-start;\n      gap: 9px;\n      padding: 9px 10px;\n      border: 1px solid var(--line);\n      border-radius: 7px;\n      background: #fbfcfd;\n      font-weight: 400;\n    }\n\n    .choice input {\n      width: auto;\n      margin-top: 4px;\n    }\n\n    .hint {\n      margin-top: 6px;\n      color: var(--muted);\n      font-size: 13px;\n    }\n\n    .actions {\n      position: sticky;\n      bottom: 0;\n      display: flex;\n      flex-wrap: wrap;\n      gap: 10px;\n      padding: 12px 0 0;\n      background: linear-gradient(to top, var(--bg) 70%, rgba(246, 247, 248, 0));\n    }\n\n    button {\n      border: 0;\n      border-radius: 7px;\n      padding: 11px 16px;\n      font: inherit;\n      font-weight: 700;\n      cursor: pointer;\n    }\n\n    .primary {\n      background: var(--accent);\n      color: #fff;\n    }\n\n    .primary:hover {\n      background: var(--accent-dark);\n    }\n\n    .secondary {\n      background: #e7ecef;\n      color: var(--ink);\n    }\n\n    .notice {\n      display: none;\n      margin-top: 10px;\n      color: var(--accent-dark);\n      font-weight: 700;\n    }\n\n    .warning {\n      color: var(--warn);\n    }\n\n    @media (max-width: 640px) {\n      main {\n        width: min(100% - 18px, 920px);\n        padding-top: 18px;\n      }\n\n      h1 {\n        font-size: 24px;\n      }\n\n      section {\n        padding: 14px;\n      }\n\n      .actions {\n        display: grid;\n      }\n    }\n  </style>\n</head>\n<body>\n  <main>\n    <header>\n      <h1>שאלון קצר לאפיון מערכת הזמנות</h1>\n      <p class=\"intro\">המטרה היא להבין איך העסק עובד היום, כדי לבנות מערכת CRM והזמנות שמתאימה בפועל לעבודה היומיומית.</p>\n    </header>\n\n    <form id=\"questionnaire\">\n      <section>\n        <h2>פרטי העסק</h2>\n        <div class=\"field\">\n          <label for=\"businessName\">שם העסק</label>\n          <input id=\"businessName\" name=\"שם העסק\" autocomplete=\"organization\">\n        </div>\n        <div class=\"field\">\n          <label for=\"contactName\">שם איש קשר</label>\n          <input id=\"contactName\" name=\"שם איש קשר\" autocomplete=\"name\">\n        </div>\n        <div class=\"field\">\n          <label for=\"contactPhone\">טלפון</label>\n          <input id=\"contactPhone\" name=\"טלפון\" autocomplete=\"tel\">\n        </div>\n      </section>\n\n      <section>\n        <h2>היקף פעילות</h2>\n        <div class=\"field\">\n          <label for=\"customerCount\">כמה לקוחות קיימים יש בערך?</label>\n          <input id=\"customerCount\" name=\"כמות לקוחות קיימים\" placeholder=\"לדוגמה: 200 / 800 / לא יודע\">\n        </div>\n        <div class=\"field\">\n          <label for=\"ordersCount\">כמה הזמנות יש בערך ביום או בשבוע?</label>\n          <input id=\"ordersCount\" name=\"כמות הזמנות\" placeholder=\"לדוגמה: 10 ביום / 60 בשבוע\">\n        </div>\n        <div class=\"field\">\n          <label for=\"productCount\">כמה מוצרים / שקים שונים יש בערך בקטלוג?</label>\n          <input id=\"productCount\" name=\"כמות מוצרים\" placeholder=\"לדוגמה: 40 / 150 / לא יודע\">\n        </div>\n      </section>\n\n      <section>\n        <h2>לקוחות והזמנות</h2>\n        <div class=\"field\">\n          <label>האם לקוח יכול להזמין כמה מוצרים באותה הזמנה?</label>\n          <div class=\"choices\">\n            <label class=\"choice\"><input type=\"radio\" name=\"כמה מוצרים בהזמנה\" value=\"כן\"> כן</label>\n            <label class=\"choice\"><input type=\"radio\" name=\"כמה מוצרים בהזמנה\" value=\"לא, בדרך כלל מוצר אחד\"> לא, בדרך כלל מוצר אחד</label>\n            <label class=\"choice\"><input type=\"radio\" name=\"כמה מוצרים בהזמנה\" value=\"לא בטוח\"> לא בטוח</label>\n          </div>\n        </div>\n        <div class=\"field\">\n          <label for=\"manualOrders\">באילו מקרים בעל העסק יפתח הזמנה ידנית?</label>\n          <textarea id=\"manualOrders\" name=\"מקרים להזמנה ידנית\" placeholder=\"לדוגמה: לקוחות מבוגרים, הזמנות טלפוניות, לקוח שלא מסתדר עם האתר\"></textarea>\n        </div>\n        <div class=\"field\">\n          <label for=\"specialCustomers\">האם יש לקוחות עם תנאים מיוחדים?</label>\n          <textarea id=\"specialCustomers\" name=\"לקוחות עם תנאים מיוחדים\" placeholder=\"לדוגמה: מחיר קבוע, הנחה, תשלום אחרי אספקה, חוב פתוח\"></textarea>\n        </div>\n      </section>\n\n      <section>\n        <h2>קטלוג ומחירים</h2>\n        <div class=\"field\">\n          <label>איך נכון להציג מוצרים?</label>\n          <div class=\"choices\">\n            <label class=\"choice\"><input type=\"radio\" name=\"מבנה קטלוג\" value=\"מותג/סדרה ואז בחירת סוג, טעם ומשקל\"> מותג/סדרה ואז בחירת סוג, טעם ומשקל</label>\n            <label class=\"choice\"><input type=\"radio\" name=\"מבנה קטלוג\" value=\"רשימת שקים נפרדים\"> רשימת שקים נפרדים</label>\n            <label class=\"choice\"><input type=\"radio\" name=\"מבנה קטלוג\" value=\"לא משנה לי\"> לא משנה לי</label>\n          </div>\n        </div>\n        <div class=\"field\">\n          <label for=\"priceRules\">איך מחירים מיוחדים והנחות עובדים היום?</label>\n          <textarea id=\"priceRules\" name=\"כללי מחירים והנחות\" placeholder=\"לדוגמה: יש לקוחות עם מחיר קבוע, מבצעים לפי מוצר, הנחות לפי לקוח\"></textarea>\n        </div>\n        <div class=\"field\">\n          <label for=\"substitutes\">האם יש מוצרים תחליפיים כשמוצר חסר?</label>\n          <textarea id=\"substitutes\" name=\"מוצרים תחליפיים\" placeholder=\"לדוגמה: אם אין עוף מציעים כבש, אם אין 12 קג מציעים 2 של 6 קג\"></textarea>\n        </div>\n      </section>\n\n      <section>\n        <h2>משלוחים</h2>\n        <div class=\"field\">\n          <label>איך החלוקה מתבצעת היום?</label>\n          <div class=\"choices\">\n            <label class=\"choice\"><input type=\"checkbox\" name=\"שיטת חלוקה\" value=\"לפי ימים קבועים\"> לפי ימים קבועים</label>\n            <label class=\"choice\"><input type=\"checkbox\" name=\"שיטת חלוקה\" value=\"לפי אזורים\"> לפי אזורים</label>\n            <label class=\"choice\"><input type=\"checkbox\" name=\"שיטת חלוקה\" value=\"לפי עיר/שכונה\"> לפי עיר/שכונה</label>\n            <label class=\"choice\"><input type=\"checkbox\" name=\"שיטת חלוקה\" value=\"ידנית לפי מה שנוח\"> ידנית לפי מה שנוח</label>\n          </div>\n        </div>\n        <div class=\"field\">\n          <label for=\"deliveryDays\">האם יש ימי חלוקה קבועים?</label>\n          <input id=\"deliveryDays\" name=\"ימי חלוקה קבועים\" placeholder=\"לדוגמה: ראשון ושלישי באזור המרכז\">\n        </div>\n        <div class=\"field\">\n          <label for=\"deliveryAreas\">אילו אזורים / ערים העסק משרת?</label>\n          <textarea id=\"deliveryAreas\" name=\"אזורי שירות\"></textarea>\n        </div>\n        <div class=\"field\">\n          <label>האם לקוח צריך לבחור מועד אספקה?</label>\n          <div class=\"choices\">\n            <label class=\"choice\"><input type=\"radio\" name=\"בחירת מועד אספקה\" value=\"כן, הלקוח בוחר מועד זמין\"> כן, הלקוח בוחר מועד זמין</label>\n            <label class=\"choice\"><input type=\"radio\" name=\"בחירת מועד אספקה\" value=\"לא, העסק קובע ומעדכן\"> לא, העסק קובע ומעדכן</label>\n            <label class=\"choice\"><input type=\"radio\" name=\"בחירת מועד אספקה\" value=\"לא בטוח\"> לא בטוח</label>\n          </div>\n          <div class=\"hint\">כרגע ידוע שצריך התראה של יומיים מראש.</div>\n        </div>\n      </section>\n\n      <section>\n        <h2>תשלומים וחשבוניות</h2>\n        <div class=\"field\">\n          <label>אילו אמצעי תשלום קיימים בפועל?</label>\n          <div class=\"choices\">\n            <label class=\"choice\"><input type=\"checkbox\" name=\"אמצעי תשלום\" value=\"קישור תשלום משולם\"> קישור תשלום משולם</label>\n            <label class=\"choice\"><input type=\"checkbox\" name=\"אמצעי תשלום\" value=\"bit דרך משולם\"> bit דרך משולם</label>\n            <label class=\"choice\"><input type=\"checkbox\" name=\"אמצעי תשלום\" value=\"Google Pay דרך משולם\"> Google Pay דרך משולם</label>\n            <label class=\"choice\"><input type=\"checkbox\" name=\"אמצעי תשלום\" value=\"מזומן לשליח\"> מזומן לשליח</label>\n            <label class=\"choice\"><input type=\"checkbox\" name=\"אמצעי תשלום\" value=\"העברה בנקאית\"> העברה בנקאית</label>\n          </div>\n        </div>\n        <div class=\"field\">\n          <label for=\"cashInvoice\">איך מפיקים חשבונית / קבלה על מזומן לשליח?</label>\n          <textarea id=\"cashInvoice\" name=\"חשבונית על מזומן לשליח\" placeholder=\"לדוגמה: דרך משולם ידנית, אחרי שהשליח חוזר, דרך מערכת אחרת\"></textarea>\n        </div>\n        <div class=\"field\">\n          <label for=\"failedPayments\">מה עושים היום עם לקוח שלא שילם?</label>\n          <textarea id=\"failedPayments\" name=\"טיפול באי תשלום\" placeholder=\"לדוגמה: מתקשרים אליו, לא מוציאים משלוח, מסמנים חוב\"></textarea>\n        </div>\n      </section>\n\n      <section>\n        <h2>עבודה יומיומית</h2>\n        <div class=\"field\">\n          <label>איפה בעל העסק יעבוד עם המערכת בעיקר?</label>\n          <div class=\"choices\">\n            <label class=\"choice\"><input type=\"radio\" name=\"מכשיר עבודה עיקרי\" value=\"טלפון\"> טלפון</label>\n            <label class=\"choice\"><input type=\"radio\" name=\"מכשיר עבודה עיקרי\" value=\"מחשב\"> מחשב</label>\n            <label class=\"choice\"><input type=\"radio\" name=\"מכשיר עבודה עיקרי\" value=\"גם וגם\"> גם וגם</label>\n          </div>\n        </div>\n        <div class=\"field\">\n          <label for=\"currentPain\">מה הכי מפריע היום בהתנהלות הקיימת?</label>\n          <textarea id=\"currentPain\" name=\"כאבים עיקריים היום\"></textarea>\n        </div>\n        <div class=\"field\">\n          <label for=\"success\">מה ייחשב הצלחה מבחינתך אחרי חודש שימוש?</label>\n          <textarea id=\"success\" name=\"מדד הצלחה אחרי חודש\"></textarea>\n        </div>\n      </section>\n\n      <section>\n        <h2>הערות נוספות</h2>\n        <div class=\"field\">\n          <label for=\"notes\">כל דבר נוסף שחשוב שנדע</label>\n          <textarea id=\"notes\" name=\"הערות נוספות\"></textarea>\n        </div>\n      </section>\n\n      <div class=\"actions\">\n        <button class=\"primary\" type=\"button\" id=\"copyAnswers\">העתקת התשובות</button>\n        <button class=\"secondary\" type=\"button\" id=\"downloadAnswers\">הורדת קובץ תשובות</button>\n        <button class=\"secondary\" type=\"reset\">ניקוי הטופס</button>\n      </div>\n      <div class=\"notice\" id=\"notice\">התשובות הועתקו. אפשר להדביק אותן בוואטסאפ או במייל.</div>\n      <p class=\"hint warning\">הטופס לא שולח מידע לשרת. אחרי המילוי יש ללחוץ על העתקת התשובות או הורדת קובץ.</p>\n    </form>\n  </main>\n\n  <script>\n    const form = document.getElementById('questionnaire');\n    const notice = document.getElementById('notice');\n\n    function collectAnswers() {\n      const data = new FormData(form);\n      const grouped = {};\n\n      for (const [key, value] of data.entries()) {\n        if (!value || !String(value).trim()) continue;\n        if (!grouped[key]) grouped[key] = [];\n        grouped[key].push(String(value).trim());\n      }\n\n      const lines = ['שאלון אפיון מערכת הזמנות', ''];\n      for (const [key, values] of Object.entries(grouped)) {\n        lines.push(`${key}: ${values.join(', ')}`);\n      }\n\n      if (lines.length === 2) {\n        lines.push('לא מולאו תשובות עדיין.');\n      }\n\n      return lines.join('\\n');\n    }\n\n    document.getElementById('copyAnswers').addEventListener('click', async () => {\n      const text = collectAnswers();\n\n      try {\n        await navigator.clipboard.writeText(text);\n        notice.style.display = 'block';\n      } catch (error) {\n        const area = document.createElement('textarea');\n        area.value = text;\n        document.body.appendChild(area);\n        area.select();\n        document.execCommand('copy');\n        area.remove();\n        notice.style.display = 'block';\n      }\n    });\n\n    document.getElementById('downloadAnswers').addEventListener('click', () => {\n      const text = collectAnswers();\n      const blob = new Blob([text], { type: 'text/plain;charset=utf-8' });\n      const url = URL.createObjectURL(blob);\n      const link = document.createElement('a');\n      link.href = url;\n      link.download = 'drive-dog-questionnaire-answers.txt';\n      document.body.appendChild(link);\n      link.click();\n      link.remove();\n      URL.revokeObjectURL(url);\n    });\n  </script>\n</body>\n</html>\n";

export default {
  async fetch() {
    return new Response(html, {
      headers: {
        "content-type": "text/html; charset=utf-8",
        "cache-control": "public, max-age=300"
      }
    });
  }
};
